<?php
namespace App\Core;
final class Router { private array $routes=[]; public function get(string $p,array $a):void{$this->add('GET',$p,$a);} public function post(string $p,array $a):void{$this->add('POST',$p,$a);} private function add($m,$p,$a):void{$this->routes[$m][]=['p'=>trim($p,'/'),'a'=>$a];} public function dispatch(string $method,string $uri):void{ $base=parse_url(App::config('base_url'),PHP_URL_PATH)?:''; $path=trim(preg_replace('#^'.preg_quote(trim($base,'/'),'#').'#','',trim($uri,'/')),'/'); if($path==='index.php'||str_ends_with($path,'/index.php')) $path=trim(substr($path,0,-9),'/'); foreach($this->routes[$method]??[] as $r){ $regex='#^'.preg_replace('#\{([a-z_]+)\}#','(?P<$1>[^/]+)',$r['p']).'$#'; if(preg_match($regex,$path,$m)){ [$c,$fn]=$r['a']; $params=array_filter($m,'is_string',ARRAY_FILTER_USE_KEY); (new $c)->$fn(...array_values($params)); return; }} http_response_code(404); echo '404 - Ruta no encontrada'; }}
